// Generated Go code from repository.dingo
// Result<T, E> becomes a generic struct with Ok/Err variants
package main

import (
	"database/sql"
	"fmt"
)

type User struct {
	ID    int
	Name  string
	Email string
}

type DBError struct {
	Code    string
	Message string
}

func (e DBError) Error() string {
	return fmt.Sprintf("[%s] %s", e.Code, e.Message)
}

// Result is the generic Result type generated by Dingo
type Result[T any, E error] struct {
	value T
	err   E
	isOk  bool
}

func Ok[E error, T any](value T) Result[T, E] {
	return Result[T, E]{value: value, isOk: true}
}

func Err[T any, E error](err E) Result[T, E] {
	return Result[T, E]{err: err, isOk: false}
}

func (r Result[T, E]) IsOk() bool  { return r.isOk }
func (r Result[T, E]) IsErr() bool { return !r.isOk }

func (r Result[T, E]) Unwrap() T {
	if !r.isOk {
		panic("called Unwrap on Err value")
	}
	return r.value
}

func (r Result[T, E]) UnwrapErr() E {
	if r.isOk {
		panic("called UnwrapErr on Ok value")
	}
	return r.err
}

// FindUserByID returns a Result that explicitly models success or failure
// Caller must handle both cases - no silent nil pointer bugs
func FindUserByID(db *sql.DB, id int) Result[User, DBError] {
	row := db.QueryRow("SELECT id, name, email FROM users WHERE id = ?", id)

	var user User
	err := row.Scan(&user.ID, &user.Name, &user.Email)
	if err == sql.ErrNoRows {
		return Err[User](DBError{Code: "NOT_FOUND", Message: "user not found"})
	}
	if err != nil {
		return Err[User](DBError{Code: "SCAN_ERROR", Message: err.Error()})
	}

	return Ok[DBError](user)
}

// TransferFunds shows Result chaining - each step must succeed
func TransferFunds(db *sql.DB, fromID int, toID int, amount float64) Result[bool, DBError] {
	// Find source user
	fromResult := FindUserByID(db, fromID)
	if fromResult.IsErr() {
		return Err[bool](fromResult.UnwrapErr())
	}

	// Find destination user
	toResult := FindUserByID(db, toID)
	if toResult.IsErr() {
		return Err[bool](toResult.UnwrapErr())
	}

	// In real code: begin transaction, update balances, commit
	fmt.Printf("Transferring $%.2f from %s to %s\n",
		amount, fromResult.Unwrap().Name, toResult.Unwrap().Name)

	return Ok[DBError](true)
}

func main() {
	// Example usage showing explicit error handling
	var db *sql.DB // Would be initialized in real code

	result := FindUserByID(db, 123)

	// Pattern: Must explicitly check and handle both cases
	if result.IsOk() {
		user := result.Unwrap()
		fmt.Printf("Found user: %s <%s>\n", user.Name, user.Email)
	} else {
		err := result.UnwrapErr()
		fmt.Printf("Error: %s\n", err.Message)
	}
}
